form:Form.form:Scripts:
		function ONLOAD()
{ 
	if (Ctrl('main').GetMode() != 'NEW')
	{   
		var v_param;
		var lic;

		//Recupero el codigo de la licencia por familiar en el parametro
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();       
		var param = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PARAMETRO"), "");	

		//Si existe el parametro - controla licencia por familiar 
		if (typeof (param.d_valor) != "undefined")
		{
			v_param = param.d_valor.toString();		
		}
		else
		{
			v_param = "";
		}   

		if(v_param != "")
		{
			//Si tiene este valor cargado, es porque es una nueva licencia         
			if(Ctrl("c_licencia_new").GetXValue() != '')
			{    
				lic = Ctrl("c_licencia_new").GetXValue();
			} 
			else
			{   
				lic = Ctrl("c_licencia").GetXValue();
			}			

			if(v_param.toString() == lic.toString())
			{			          
				Ctrl('LC_TFLIAR').SetEnabled(true);
			}         	
			else
			{			
				Ctrl('LC_TFLIAR').SetEnabled(false);			
			}					
		}
		else
		{			
			Ctrl('LC_TFLIAR').SetEnabled(false);			
		}					
	}
}
